INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('797877b0-cdaa-5ebd-a8de-7f3e8752fa2c', '670e26fd-407b-4388-8514-bd71291e9652', '___ moon is very bright tonight.', '今晚的月亮非常明亮。', 'the', 'a', 'an', 'some', '定冠詞，用於指代特定的事物。', '指特定的事物時，前面要用 the。'),
('09a8ef35-3335-5de8-bea4-c28312f25868', '24837458-0d4f-4a59-9dc7-ae944f0f278c', 'The information provided in the textbook ___ essential for the final exam.', '教科書中提供的資訊對期末考試至關重要。', 'is', 'has', 'does', 'says', 'be 動詞的第三人稱單數現在式', 'is 代表「是」或「在」，用於描述主詞的狀態或身分。'),
('5668cbcf-b4fc-5b34-80c6-206278451c10', 'c5a6bb6c-11be-4f15-9ea7-f6b983edff63', 'Every human ___ deserves to live in peace.', '每個人類都值得在和平中生活。', 'being', 'mind', 'soul', 'body', 'be (存在) + ing (名詞字尾) → 存在、生命體、本質。', '想像「being」就是「正在存在著的狀態」→ 存在、生命。');
